+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+function camelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (item && typeof item === "object" && !Array.isArray(item)) {
+      Object.assign(result, flatten(item as Record<string, unknown>, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = trimmed.indexOf("=");
+    if (separator === -1) throw new Error("Expected key=value pair.");
+    const key = camelCase(trimmed.slice(0, separator).trim());
+    let value = trimmed.slice(separator + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      values[key] = value === "true";
+      continue;
+    } else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      values[key] = Number(value);
+      continue;
+    }
+    values[key] = value;
+  }
+  return values;
+}
+
+async function read(path: string): Promise<string | undefined> {
+  try {
+    if (typeof Deno !== "undefined") return await Deno.readTextFile(path);
+    return await (await import("node:fs/promises")).readFile(path, "utf8");
+  } catch (error) {
+    if (error instanceof Error && ("name" in error) && (error.name === "NotFound" || (error as { code?: string }).code === "ENOENT")) return;
+    throw error;
+  }
+}
+
+function pathFor(directory: string, name: string, format: string): string {
+  const separator = directory.endsWith("/") || directory.endsWith("\\\\") ? "" : "/";
+  return format === ".rc" ? `${directory}${separator}.${name}rc` : `${directory}${separator}${name}${format}`;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [typeof Deno !== "undefined" ? Deno.cwd() : process.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const values: Record<string, unknown> = {};
+  let foundPath: string | undefined;
+  for (const directory of paths) {
+    let found = false;
+    for (const format of formats) {
+      const path = pathFor(directory, options.name, format);
+      const content = await read(path);
+      if (typeof content === "undefined") continue;
+      try {
+        const parsed = options.parser ? options.parser(content) : format === ".rc" ? parseRc(content) : JSON.parse(content);
+        if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error("Configuration must be a plain object.");
+        Object.assign(values, flatten(parsed));
+        foundPath ??= path;
+        found = true;
+      } catch (error) {
+        throw new ConfigParseError(path, error);
+      }
+      break;
+    }
+    if (found && !options.mergeConfigs) break;
+  }
+  return { path: foundPath, values };
+}
