+test("command - config - loads json values with CLI and env precedence", async () => {
+  const path = await fixture({
+    "app.json": JSON.stringify({ "dry-run": false, count: 0, tags: ["one", "two"], nested: { value: "ignored" } }),
+  });
+  const cmd = new Command().throwErrors()
+    .option("--dry-run", "Dry run")
+    .option("--count <count:number>", "Count")
+    .option("--tags <tag:string>", "Tag", { collect: true })
+    .env("COUNT=<count:number>", "Count")
+    .config({ name: "app", searchPaths: [path] });
+
+  const result = await cmd.parse(["--count", "2"]);
+  assertEquals(result.options, { dryRun: false, count: 2, tags: ["one", "two"] });
+  assertEquals(cmd.getConfigPath(), `${path}/app.json`);
+  assertEquals(cmd.getConfigValues(), { dryRun: false, count: 0, tags: ["one", "two"], "nested.value": "ignored" });
+});
+
+test("command - config - loads rc values", async () => {
+  const path = await fixture({
+    ".app rc": "",
+    ".apprc": "# comment\
display-name=\\"Jane Doe\\"\
enabled=false\
count=0\
",
+  });
+  const result = await new Command().throwErrors()
+    .option("--display-name <name>", "Name")
+    .option("--enabled", "Enabled")
+    .option("--count <count:number>", "Count")
+    .config({ name: "app", searchPaths: [path] })
+    .parse([]);
+  assertEquals(result.options, { displayName: "Jane Doe", enabled: false, count: 0 });
+});
+
+test("command - config - merges paths in order and inherits into subcommands", async () => {
+  const first = await fixture({ "app.json": JSON.stringify({ verbose: true, count: 1 }) });
+  const second = await fixture({ "app.json": JSON.stringify({ count: 2 }) });
+  const child = new Command().option("--count <count:number>", "Count")
+    .config({ name: "child", searchPaths: [second] });
+  const cmd = new Command().throwErrors().globalOption("--verbose", "Verbose")
+    .config({ name: "app", searchPaths: [first, second], mergeConfigs: true })
+    .command("child", child);
+  const result = await cmd.parse(["child"]);
+  assertEquals(result.options, { verbose: true, count: 2 });
+  assertEquals(child.getConfigValues(), { verbose: true, count: 2 });
+});
+
+test("command - config - reports malformed and invalid values", async () => {
