+function camelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (item && typeof item === "object" && !Array.isArray(item)) {
+      Object.assign(result, flatten(item as Record<string, unknown>, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
